css:
.ps-wiki-article-footer { padding-block: var(--pds-space-2); border-block-start: 1px solid var(--pds-border-subtle); font-family: var(--pds-font-body); color: var(--pds-text-primary); }
.ps-wiki-article-footer__section-heading { font-size: 1.25rem; font-weight: 600; margin-block-end: var(--pds-space-1); }
.ps-wiki-article-footer__category-list { list-style: none; padding: 0; display: flex; flex-wrap: wrap; gap: var(--pds-space-05); margin-block-end: var(--pds-space-2); }
.ps-wiki-article-footer__ref-list { padding-inline-start: 1.5rem; margin-block-end: var(--pds-space-2); color: var(--pds-text-secondary); }
.ps-wiki-article-footer__actions { margin-block-start: var(--pds-space-2); text-align: end; }
.ps-wiki-article-footer__edit-link { color: var(--pds-link); }
